  ('a07b1900-0000-4000-8000-000000000000','a07b0000-0000-4000-8000-000000000000','確認テスト ─ 報連相を武器にする','quiz',NULL,NULL,NULL,3,2),
  ('a07b2900-0000-4000-8000-000000000000','a07b0000-0000-4000-8000-000000000000','確認テスト ─ 後輩を導く','quiz',NULL,NULL,NULL,3,4),
  ('a07b3900-0000-4000-8000-000000000000','a07b0000-0000-4000-8000-000000000000','確認テスト ─ 権限がなくても巻き込む','quiz',NULL,NULL,NULL,3,6)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a07b1900-0000-4000-8000-000000000000','報連相の本質を一行で言うと、その主語は誰か。','伝える自分','判断し、動く相手','監督する上司','情報そのもの','B',0),
('a07b1900-0000-4000-8000-000000000000','効く報連相が相手に渡す三つとは何か。','結論・判断材料・相手にしてほしいこと','経過・感想・反省','時系列・全体像・自分の意見','謝罪・言い訳・報告','A',1),
('a07b1900-0000-4000-8000-000000000000','権限のないあなたが依頼を断るとき、本文が示す型はどれか。','理由を詳しく説明して全部引き受ける','「できません」と早めにはっきり伝える','代案を添えて返す','上司に判断を丸投げする','C',2),
('a07b2900-0000-4000-8000-000000000000','本文が言う「育てる」の本質はどれか。','やり方を漏れなく教えきること','やってあげることから、やらせてみることへ移っていくこと','背中を見せて自分で覚えさせること','失敗させないよう先回りして手を出すこと','B',0),
('a07b2900-0000-4000-8000-000000000000','「任せる」ではなく「任せてみる」とされる理由はどれか。','後輩の実力がまだ足りないから','権限がないので責任を渡せないから','手は離すが目は離さず、すぐ受け止める距離だから','上司にそう指示されているから','C',1),
('a07b2900-0000-4000-8000-000000000000','フィードバックについて本文が決定的に大事とするのはどれか。','人格ではなく、行動に返す','できたところより、できなかったところを返す','その場では言わず、後でまとめて返す','性格の傾向を指摘して自覚させる','A',2),
('a07b3900-0000-4000-8000-000000000000','本文が言う「影響力」の正体はどれか。','説得の技術','正論の強さ','肩書きと役職','日々の関わりで積み上げた信頼の残高','D',0),
('a07b3900-0000-4000-8000-000000000000','信頼残高は誰に貯まると本文は言うか。','先に与えた人','先に引き出そうとする人','正しい提案をする人','見返りを数える人','A',1),
('a07b3900-0000-4000-8000-000000000000','権限のないあなたの提案を通すため、どの向きで語るべきか。','自分の正しさの主張','相手にとって何が得か','全部を一度に変える大きな絵','データと論理の完璧さ','B',2);
